parameters.jsCode:
const { tenant_id, score, testimonial, name, company, industry, agent_name, loom_url } = $json.body;
const isPositive = parseInt(score) >= 8;
const isNeutral = parseInt(score) >= 6 && parseInt(score) < 8;

return [{ json: { tenant_id, score: parseInt(score), testimonial, name, company, industry, agent_name, loom_url: loom_url || '', isPositive, isNeutral, type: isPositive ? 'positive' : (isNeutral ? 'neutral' : 'negative') } }];

